function initMenu(){let t=document.getElementById("nav-toggle"),o=document.getElementById("nav-menu");var e=document.querySelectorAll(".nav__menu a");t&&o&&(t.addEventListener("click",()=>{o.classList.toggle("show-menu"),t.classList.toggle("show-icon")}),e.forEach(e=>{e.addEventListener("click",()=>{o.classList.remove("show-menu"),t.classList.remove("show-icon")})}))}function initCursorFollower(){if(window.matchMedia("(min-width: 1024px)").matches&&window.matchMedia("(hover: hover)").matches){let c=document.querySelector(".cursor-follower");if(c){let t=0,o=0,n=0,i=0;document.addEventListener("mousemove",e=>{t=e.clientX,o=e.clientY}),!function e(){n+=.15*(t-n),i+=.15*(o-i),c.style.left=n+"px",c.style.top=i+"px",requestAnimationFrame(e)}(),document.querySelectorAll(".card").forEach(e=>{e.addEventListener("mouseenter",()=>{c.classList.add("active"),c.dataset.text="View Project"}),e.addEventListener("mouseleave",()=>{c.classList.remove("active"),c.dataset.text=""})})}}}function initAccordion(){var e=document.querySelectorAll(".questions__item");if(e.length){let o=e=>{var t=e.querySelector(".questions__content");t&&(e.classList.contains("accordion-open")?(t.style.height="",e.classList.remove("accordion-open")):(t.style.height=t.scrollHeight+"px",e.classList.add("accordion-open")))};e.forEach(t=>{var e=t.querySelector(".questions__header");e&&e.addEventListener("click",()=>{var e=document.querySelector(".accordion-open");o(t),e&&e!==t&&o(e)})})}}document.addEventListener("DOMContentLoaded",()=>{initMenu(),initCursorFollower(),initAccordion()});